class Relation:
    def __init__(self, name, attributes, primary_key):
        self.name = name
        self.attributes = attributes  # List of attribute names
        self.primary_key = primary_key  # Primary key attribute(s)
        self.tuples = []  # List of dictionaries

    def insert(self, tuple_data):
        # Entity Integrity Check
        for key_attr in self.primary_key:
            if key_attr not in tuple_data or tuple_data[key_attr] is None:
                raise ValueError("Primary Key cannot be NULL - Entity Integrity Violation")

        # Check for duplicate primary key
        for existing in self.tuples:
            if all(existing[pk] == tuple_data[pk] for pk in self.primary_key):
                raise ValueError("Duplicate Primary Key")

        self.tuples.append(tuple_data)

# Example: Student Relation
Student = Relation("Student", ["SID", "Name", "Age", "Dept"], ["SID"])
Student.insert({"SID": 1, "Name": "Amit", "Age": 20, "Dept": "CS"})

#include <stdio.h>
#include <string.h>

typedef struct {
    int sid;
    char name[50];
    int age;
    char dept[10];
} Student;

int check_entity_integrity(Student *s) {
    // Entity Integrity: Primary Key (sid) cannot be NULL (0 in C)
    if (s->sid == 0) {
        printf("Error: Primary Key cannot be NULL\n");
        return 0;
    }
    return 1;
}

int check_domain_constraints(Student *s) {
    // Domain constraints
    if (s->age < 0 || s->age > 150) {
        printf("Error: Age must be between 0 and 150\n");
        return 0;
    }
    if (strlen(s->name) == 0) {
        printf("Error: Name cannot be empty\n");
        return 0;
    }
    return 1;
}

int insert_student(Student students[], int *count, Student new_student) {
    // Check Entity Integrity
    if (!check_entity_integrity(&new_student)) return 0;

    // Check Domain Constraints
    if (!check_domain_constraints(&new_student)) return 0;

    // Check for duplicate primary key
    for (int i = 0; i < *count; i++) {
        if (students[i].sid == new_student.sid) {
            printf("Error: Duplicate Primary Key\n");
            return 0;
        }
    }

    students[*count] = new_student;
    (*count)++;
    return 1;
}
